#include <bits/stdc++.h>
using namespace std;

const int N=210;

int n,m,sx,sy,k,d[N],t[N],f[N][N][N],q[N],hh,tt;
char g[N][N];

int main(){
	scanf("%d%d%d%d%d",&n,&m,&sx,&sy,&k);
	for(int i=1;i<=n;i++)
		scanf("%s",g[i]+1);
	for(int i=1,u,v;i<=k;i++){
		scanf("%d%d%d",&u,&v,&d[i]);
		t[i]=v-u+1;
	}
	for(int i=k;i;i--){
		if(d[i]==1){
			for(int y=1;y<=m;y++){
				hh=1,tt=0;
				for(int x=1;x<=n;x++){
					if(g[x][y]=='x'){
						hh=tt+1;
						continue;
					}
					while(hh<=tt && q[hh]<x-t[i]) hh++;
					while(hh<=tt && f[i+1][q[tt]][y]-q[tt]<=f[i+1][x][y]-x) tt--;
					q[++tt]=x;
					f[i][x][y]=f[i+1][q[hh]][y]+x-q[hh];
				}
			}
		}
		if(d[i]==2){
			for(int y=1;y<=m;y++){
				hh=1,tt=0;
				for(int x=n;x;x--){
					if(g[x][y]=='x'){
						hh=tt+1;
						continue;
					}
					while(hh<=tt && q[hh]>x+t[i]) hh++;
					while(hh<=tt && f[i+1][q[tt]][y]+q[tt]<=f[i+1][x][y]+x) tt--;
					q[++tt]=x;
					f[i][x][y]=f[i+1][q[hh]][y]+q[hh]-x;
				}
			}
		}
		if(d[i]==3){
			for(int x=1;x<=n;x++){
				hh=1,tt=0;
				for(int y=1;y<=m;y++){
					if(g[x][y]=='x'){
						hh=tt+1;
						continue;
					}
					while(hh<=tt && q[hh]<y-t[i]) hh++;
					while(hh<=tt && f[i+1][x][q[tt]]-q[tt]<=f[i+1][x][y]-y) tt--;
					q[++tt]=y;
					f[i][x][y]=f[i+1][x][q[hh]]+y-q[hh];
				}
			}
		}
		if(d[i]==4){
			for(int x=1;x<=n;x++){
				hh=1,tt=0;
				for(int y=m;y;y--){
					if(g[x][y]=='x'){
						hh=tt+1;
						continue;
					}
					while(hh<=tt && q[hh]>y+t[i]) hh++;
					while(hh<=tt && f[i+1][x][q[tt]]+q[tt]<=f[i+1][x][y]+y) tt--;
					q[++tt]=y;
					f[i][x][y]=f[i+1][x][q[hh]]+q[hh]-y;
				}
			}
		}
	}
	printf("%d",f[1][sx][sy]);
	return 0;
}
